// ingest.go
type (
	MyNewRequest  = ingest.MyNewRequest
	MyNewResponse = struct{}
	MyNewHandler  httptransport.Handler[MyNewRequest, MyNewResponse]
)

func (h *handler) MyNew() MyNewHandler {
	return httptransport.NewHandler(
		func(ctx context.Context, r *http.Request) (MyNewRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return MyNewRequest{}, err }
			// decode body...
			return MyNewRequest{Namespace: ns}, nil
		},
		func(ctx context.Context, req MyNewRequest) (MyNewResponse, error) {
			_, err := h.service.MyNew(ctx, req)
			return MyNewResponse{}, err
		},
		commonhttp.EmptyResponseEncoder[MyNewResponse](http.StatusNoContent),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("MyNew"),
			httptransport.WithErrorEncoder(errorEncoder()),
		)...,
	)
}

// app/common/ingest.go (wiring side)
import (
	"github.com/openmeterio/openmeter/openmeter/ingest/ingestadapter"
	"go.opentelemetry.io/otel/metric"
	"go.opentelemetry.io/otel/trace"
)

func NewInstrumentedCollector(
	collector ingest.Collector,
	metricMeter metric.Meter,
	tracer trace.Tracer,
) (ingest.Collector, error) {
	return ingestadapter.WithTelemetry(collector, metricMeter, tracer)
}
